// src/Login.js
import React, { useMemo, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import { motion, useMotionValue, useTransform } from "framer-motion";
import { Truck, Loader2, Eye, EyeOff, LogIn } from "lucide-react";

const supabase = createClient(
    process.env.REACT_APP_SUPABASE_URL,
    process.env.REACT_APP_SUPABASE_KEY
);

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [show, setShow] = useState(false);
    const [err, setErr] = useState("");
    const [loading, setLoading] = useState(false);

    // 3D parallax için mouse imzası
    const mx = useMotionValue(0.5);
    const my = useMotionValue(0.5);
    const rotateX = useTransform(my, [0, 1], [8, -8]);
    const rotateY = useTransform(mx, [0, 1], [-10, 10]);
    const glowX = useTransform(mx, [0, 1], ["0%", "100%"]);

    const handlePointer = (e) => {
        const rect = e.currentTarget.getBoundingClientRect();
        mx.set((e.clientX - rect.left) / rect.width);
        my.set((e.clientY - rect.top) / rect.height);
    };

    const particles = useMemo(
        () =>
            Array.from({ length: 18 }).map((_, i) => ({
                id: i,
                s: 10 + Math.random() * 36,
                x: Math.random() * 100,
                y: Math.random() * 100,
                d: 10 + Math.random() * 30,
                t: 12 + Math.random() * 16,
            })),
        []
    );

    const handleLogin = async (e) => {
        e.preventDefault();
        setErr("");
        setLoading(true);

        try {
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();

            if (error || !data) {
                setErr("❌ Hatalı kullanıcı adı veya şifre!");
                return;
            }

            localStorage.setItem("kullanici", JSON.stringify(data));

            const reelUser =
                data.Reel_kullanici ??
                data.reel_kullanici ??
                data.reelUserName ??
                data.reel_username ??
                "";
            const reelPass =
                data.Reel_sifre ??
                data.reel_sifre ??
                data.reelPassword ??
                data.reel_password ??
                "";

            if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
            if (reelPass) localStorage.setItem("Reel_sifre", reelPass);
            if (reelUser && reelPass) {
                localStorage.setItem(
                    "reelCreds",
                    JSON.stringify({ userName: reelUser, password: reelPass })
                );
            }

            onLoginSuccess?.();
        } catch (e2) {
            console.error(e2);
            setErr("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="logi-root" onPointerMove={handlePointer}>
            <style>{css}</style>

            {/* Arkaplan: animated gradient + hareketli şeritli yol */}
            <div className="bg">
                <div className="bg-gradient" />
                <div className="road">
                    <div className="road-line" />
                </div>

                {/* Uçuşan “konteyner” parçacıkları */}
                {particles.map((p) => (
                    <motion.div
                        key={p.id}
                        className="particle"
                        style={{
                            width: p.s,
                            height: p.s * 0.66,
                            left: `${p.x}%`,
                            top: `${p.y}%`,
                            animationDuration: `${p.t}s`,
                            borderRadius: 8,
                        }}
                        initial={{ opacity: 0, y: p.d }}
                        animate={{ opacity: [0, 1, 1, 0], y: [p.d, -p.d * 2] }}
                        transition={{
                            repeat: Infinity,
                            repeatType: "loop",
                            ease: "easeInOut",
                            duration: p.t,
                            times: [0, 0.15, 0.85, 1],
                            delay: (p.id % 5) * 0.5,
                        }}
                    />
                ))}
            </div>

            {/* Sol hero */}
            <motion.div
                className="hero"
                initial={{ opacity: 0, y: 14 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.55 }}
            >
                <span className="badge">
                    <Truck size={16} />
                    LogiPro · Lojistik Operasyon
                </span>
                <h1>
                    Akıllı Lojistik için <em>güvenli</em> giriş
                </h1>
                <p>
                    Canlı sevkiyat, depo ve filo bilgilerine anında erişim.
                    Rota optimizasyonu ve uçtan uca görünürlük.
                </p>
            </motion.div>

            {/* Login kartı (3D parallax + neon glow) */}
            <motion.div
                className="card"
                style={{ rotateX, rotateY }}
                initial={{ opacity: 0, y: 18, scale: 0.98 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ duration: 0.6, ease: [0.2, 0.8, 0.2, 1] }}
            >
                <div className="glow" style={{ left: glowX }} />

                <div className="card-head">
                    <LogIn size={18} />
                    <span>Giriş</span>
                </div>

                <form onSubmit={handleLogin} className="form">
                    {/* Floating label input */}
                    <div className="field">
                        <input
                            id="user"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            autoComplete="username"
                            placeholder=" "
                        />
                        <label htmlFor="user">Kullanıcı Adı</label>
                        <div className="focus-ring" />
                    </div>

                    <div className="field">
                        <input
                            id="pass"
                            type={show ? "text" : "password"}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            autoComplete="current-password"
                            placeholder=" "
                        />
                        <label htmlFor="pass">Şifre</label>
                        <button
                            type="button"
                            className="toggle"
                            aria-label={show ? "Şifreyi gizle" : "Şifreyi göster"}
                            onClick={() => setShow((s) => !s)}
                        >
                            {show ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                        <div className="focus-ring" />
                    </div>

                    {err && (
                        <motion.div
                            className="alert"
                            initial={{ opacity: 0, y: -6 }}
                            animate={{ opacity: 1, y: 0 }}
                        >
                            {err}
                        </motion.div>
                    )}

                    <motion.button
                        type="submit"
                        className="btn"
                        disabled={loading}
                        whileHover={{ y: -1 }}
                        whileTap={{ y: 1, scale: 0.995 }}
                    >
                        {loading ? (
                            <span className="btn-inner">
                                <Loader2 className="spin" size={16} />
                                Giriş yapılıyor…
                            </span>
                        ) : (
                            "Giriş"
                        )}
                        {/* Ripple */}
                        <span className="ripple" />
                    </motion.button>

                    {/* İnce yükleme ilerlemesi (buton altında) */}
                    <motion.div
                        className="progress"
                        animate={{ scaleX: loading ? 1 : 0 }}
                        style={{ originX: 0 }}
                        transition={{ duration: 1.2, ease: "easeInOut", repeat: loading ? Infinity : 0 }}
                    />

                    <p className="terms">
                        Devam ederek <a href="#">Kullanım Koşulları</a>’nı kabul etmiş olursunuz.
                    </p>
                </form>
            </motion.div>
        </div>
    );
}

/* ====== Modern, animasyonlu, tek-dosya CSS ====== */
const css = `
:root{
  --bg0:#050a13;
  --bg1:#081427;
  --card:#0b1d38f0;
  --glass:rgba(255,255,255,.06);
  --border:rgba(255,255,255,.14);
  --text:#e8f0ff;
  --muted:#9db0c9;
  --primary:#38bdf8;   /* sky-400 */
  --primary2:#0ea5e9;  /* sky-500 */
  --accent:#22d3ee;    /* cyan-400 */
  --danger:#ef4444;
  --shadow: 0 30px 80px rgba(2,8,23,.65);
}

*{box-sizing:border-box}
html,body,#root,.logi-root{height:100%}
body{margin:0;background:var(--bg0);color:var(--text);font:14px/1.45 Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, "Helvetica Neue", Arial}

.logi-root{
  display:grid;
  grid-template-columns: 1.1fr 1fr;
  gap: clamp(18px, 4vw, 40px);
  padding: clamp(16px, 3vw, 36px);
  place-items:center;
  position:relative;
  overflow:hidden;
}
@media (max-width: 980px){
  .logi-root{ grid-template-columns: 1fr; }
}

/* BACKGROUND */
.bg{position:absolute; inset:0; z-index:0; overflow:hidden}
.bg-gradient{
  position:absolute; inset:0;
  background:
    radial-gradient(1200px 700px at 110% -10%, rgba(56,189,248,.25), transparent 60%),
    radial-gradient(900px 500px at -5% 110%, rgba(34,211,238,.18), transparent 55%),
    linear-gradient(180deg, var(--bg0), var(--bg1));
  filter: saturate(120%);
  animation: hue 18s ease-in-out infinite alternate;
}
@keyframes hue { from{ filter: hue-rotate(0deg) } to{ filter: hue-rotate(12deg) } }

.road{
  position:absolute; left:50%; top:-10%;
  width: 540px; height: 140%;
  transform: translateX(-50%) skewY(-10deg) rotate(-8deg);
  background: linear-gradient(180deg, rgba(255,255,255,.06), rgba(255,255,255,.03), transparent);
  filter: blur(18px);
  opacity:.7;
}
.road-line{
  position:absolute; left:50%; top:0; transform:translateX(-50%);
  width: 6px; height: 100%;
  background:
    repeating-linear-gradient( to bottom, rgba(255,255,255,.8) 0 20px, transparent 20px 50px );
  filter: blur(0.5px);
  animation: dash 2.6s linear infinite;
  opacity:.7;
}
@keyframes dash { to{ background-position-y: 100% } }

.particle{
  position:absolute;
  background: linear-gradient(120deg, rgba(56,189,248,.45), rgba(34,211,238,.2));
  border: 1px solid rgba(255,255,255,.2);
  box-shadow: 0 12px 30px rgba(2,8,23,.35);
}

/* HERO */
.hero{ position:relative; z-index:1; align-self:center; justify-self:stretch; max-width:720px }
.badge{
  display:inline-flex; gap:8px; align-items:center;
  padding:8px 12px; border-radius:999px; border:1px solid var(--border);
  background: var(--glass); backdrop-filter: blur(8px);
  color:#d9e6ff; font-size:12px;
}
.hero h1{
  margin: 12px 0 6px;
  font-size: clamp(28px, 5vw, 48px);
  line-height:1.08; font-weight:900; letter-spacing:-0.02em;
}
.hero h1 em{ color: var(--primary); font-style: normal; text-shadow: 0 0 24px rgba(56,189,248,.25) }
.hero p{ color: var(--muted); margin: 8px 0 0; max-width: 56ch }

/* CARD / FORM */
.card{
  position:relative; z-index:2;
  width: min(460px, 92vw);
  border-radius: 22px;
  background: var(--card);
  border: 1px solid var(--border);
  box-shadow: var(--shadow);
  padding: 20px;
  perspective: 1000px;
  transform-style: preserve-3d;
  overflow: hidden;
}
.glow{
  position:absolute; top:-10%; width: 40%; height: 130%;
  background: radial-gradient(300px 600px at 50% 50%, rgba(56,189,248,.22), transparent 60%);
  filter: blur(28px); opacity:.9;
  transition: left .25s ease;
  pointer-events:none;
}

.card-head{
  display:flex; align-items:center; gap:8px;
  padding-bottom:12px; margin-bottom:12px;
  border-bottom: 1px solid var(--border);
  font-weight:800; letter-spacing:.2px;
}

.form{ display:grid; gap:14px }

/* Floating label fields */
.field{ position:relative }
.field input{
  width:100%;
  border:1px solid var(--border);
  background: rgba(255,255,255,.05);
  color: var(--text);
  border-radius: 14px;
  padding: 14px 44px 14px 14px;
  outline:none;
  transition: border-color .2s, box-shadow .2s, background .2s;
  backdrop-filter: blur(6px);
}
.field input::placeholder{ color: transparent } /* floating */
.field label{
  position:absolute; left:12px; top:50%; transform: translateY(-50%);
  color:#cfe0ff; font-size: 13px; pointer-events:none;
  transition: all .18s ease;
  background: transparent; padding: 0 6px;
}
.field .toggle{
  position:absolute; right:10px; top:50%; transform: translateY(-50%);
  background:transparent; border:0; color:#d0def7; cursor:pointer; padding:4px;
}
.field .toggle:hover{ color:#fff }

.field input:focus{
  border-color: rgba(56,189,248,.6);
  box-shadow: 0 0 0 5px rgba(56,189,248,.16);
  background: rgba(255,255,255,.07);
}
.field input:not(:placeholder-shown) + label,
.field input:focus + label{
  top: 0; transform: translateY(-50%) scale(.92);
  color:#a9c9ff; background: var(--card);
}

/* subtle inner focus ring */
.focus-ring{
  pointer-events:none;
  position:absolute; inset:-2px; border-radius:16px;
  border: 1px solid rgba(56,189,248,.28);
  opacity: 0; transform: scale(.98);
  transition: .2s;
}
.field input:focus ~ .focus-ring{ opacity:1; transform: scale(1) }

/* Alert */
.alert{
  background: rgba(239,68,68,.12);
  border:1px solid rgba(239,68,68,.35);
  color:#ffd6d6; border-radius: 12px; padding:10px 12px; font-size:13px;
}

/* Button + ripple + progress */
.btn{
  position:relative;
  width:100%; border:0; cursor:pointer;
  border-radius: 14px;
  background: linear-gradient(100deg, var(--primary2), var(--primary) 60%, var(--accent));
  color:white; font-weight:800; letter-spacing:.2px;
  padding: 12px 14px; box-shadow: 0 12px 40px rgba(14,165,233,.25);
  transition: filter .2s, transform .06s;
  overflow:hidden;
}
.btn:hover{ filter: brightness(1.06) }
.btn:active{ transform: translateY(1px) }
.btn:disabled{ opacity:.7; cursor:not-allowed }
.btn-inner{ display:inline-flex; gap:10px; align-items:center }
.spin{ animation:spin 1s linear infinite }
@keyframes spin{ to{ transform: rotate(360deg) } }

.ripple{
  content:\"\"; position:absolute; inset:0; pointer-events:none;
  background: radial-gradient(400px 400px at var(--mx,50%) var(--my,50%), rgba(255,255,255,.25), transparent 45%);
  opacity:0; transition: opacity .25s;
}
.btn:hover .ripple{ opacity:.45 }

.progress{
  height: 3px; margin-top: 8px;
  background: linear-gradient(90deg, var(--primary2), var(--primary), var(--accent));
  border-radius: 6px; transform: scaleX(0);
}

/* Links */
.terms{
  text-align:center; color: var(--muted); font-size:12px; margin: 8px 0 0;
}
.terms a{ color:#dff0ff; text-decoration: none; border-bottom:1px dashed rgba(255,255,255,.25) }
.terms a:hover{ color:white; border-bottom-color: white }
`;
